#!/usr/bin/env python3
"""Swap placeholder hero to cropped hillside estate photo"""
import base64, os, sys
if not os.path.exists("frontend/public"):
    os.makedirs("frontend/public", exist_ok=True)
content = base64.b64decode("")
with open("frontend/public/placeholder-hero.jpg", "wb") as f:
    f.write(content)
print(f"  Updated: frontend/public/placeholder-hero.jpg ({len(content):,} bytes)")
print("\nNow run:")
print('  git add -A && git commit -m "Swap hero placeholder to hillside estate" && git push')
